"use client";
import { useState, useEffect, useRef } from "react";
import { useRouter } from "next/navigation";
import { useSession, signOut } from "next-auth/react";
import axios from "axios";
import { toast } from "react-toastify";
import { FaBlog, FaTrash } from "react-icons/fa6";
import { CgProfile } from "react-icons/cg";
import { FiLogOut, FiEdit } from "react-icons/fi";
import BlogList from "./BlogList/page.js";
import ReportedBlogs from "./ReportedBlogs/page.js";

export default function AdminDashboard() {
  const router = useRouter();
  const { data: session, status } = useSession();
  const [reportedBlogs, setReportedBlogs] = useState([]);
  const [allBlogs, setAllBlogs] = useState([]);
  const [trashedBlogs, setTrashedBlogs] = useState([]);
  const [view, setView] = useState("reported"); // "reported", "all", or "trash"
  const [adminDetails, setAdminDetails] = useState(null);
  const [showProfileDropdown, setShowProfileDropdown] = useState(false);
  const [showUpdateModal, setShowUpdateModal] = useState(false);
  const [editProfile, setEditProfile] = useState({
    username: "",
    email: "",
    phone: "",
    password: "",
    confirmPassword: "",
  });
  const [sortOption, setSortOption] = useState("createdAt-desc"); // Combined sort by and order
  const hasRedirected = useRef(false);

  // Handle redirects in useEffect
  useEffect(() => {
    if (hasRedirected.current) return;

    if (status === "loading") return;

    if (status === "authenticated" && session?.user?.role !== "admin") {
      hasRedirected.current = true;
      router.push("/homepage");
    } else if (status === "unauthenticated") {
      hasRedirected.current = true;
      router.push("/homepage");
    }
  }, [status, session, router]);

  // Fetch admin details
  useEffect(() => {
    if (status === "authenticated" && session?.user?.id) {
      axios
        .get(`http://localhost:5000/api/user/${session.user.id}`)
        .then((response) => {
          setAdminDetails(response.data);
          setEditProfile({
            username: response.data.username,
            email: response.data.email,
            phone: response.data.phone,
            password: "",
            confirmPassword: "",
          });
        })
        .catch((error) => {
          console.error("Error fetching admin details:", error);
          toast.error("Failed to fetch admin details");
        });
    }
  }, [status, session]);

  // Fetch reported blogs
  useEffect(() => {
    if (view === "reported") {
      axios
        .get("http://localhost:5000/api/reportblogs")
        .then((response) => {
          const blogs = Array.isArray(response.data) ? response.data : response.data.blogs || [];
          setReportedBlogs(blogs);
        })
        .catch((error) => {
          console.error("Error fetching reported blogs:", error);
          toast.error("Failed to fetch reported blogs");
        });
    }
  }, [view]);

  // Fetch all blogs
  useEffect(() => {
    if (view === "all") {
      axios
        .get("http://localhost:5000/api/bloglist")
        .then((response) => {
          const blogs = response.data.blogs || [];
          setAllBlogs(blogs);
        })
        .catch((error) => {
          console.error("Error fetching all blogs:", error);
          toast.error("Failed to fetch blogs");
        });
    }
  }, [view]);

  // Fetch trashed blogs
  useEffect(() => {
    if (view === "trash") {
      axios
        .get("http://localhost:5000/api/admintrash")
        .then((response) => {
          const blogs = response.data.blogs || [];
          setTrashedBlogs(blogs);
        })
        .catch((error) => {
          console.error("Error fetching trashed blogs:", error);
          toast.error("Failed to fetch trashed blogs");
        });
    }
  }, [view]);

  // Handle deny report
  const handleDenyReport = async (blogId) => {
    try {
      const res = await axios.patch(`http://localhost:5000/api/denyreport/${blogId}`);
      setReportedBlogs(reportedBlogs.filter((blog) => blog._id !== blogId));
      toast.success(res.data.message);
    } catch (error) {
      console.error("Error denying report:", error);
      toast.error(error.response?.data?.message || "Failed to deny report");
    }
  };

  // Handle delete blog
  const handleDeleteBlog = async (blogId) => {
    try {
      const res = await axios.delete(`http://localhost:5000/api/admindelblog/${blogId}`);
      if (view === "reported") {
        setReportedBlogs(reportedBlogs.filter((blog) => blog._id !== blogId));
      } else if (view === "all") {
        setAllBlogs(allBlogs.filter((blog) => blog._id !== blogId));
      }
      toast.success(res.data.message);
    } catch (error) {
      console.error("Error deleting blog:", error);
      toast.error(error.response?.data?.message || "Failed to delete blog");
    }
  };

  // Handle restore blog
  const handleRestoreBlog = async (blogId) => {
    try {
      const res = await axios.put(`http://localhost:5000/api/adminrestore/${blogId}`);
      setTrashedBlogs(trashedBlogs.filter((blog) => blog._id !== blogId));
      toast.success(res.data.message);
    } catch (error) {
      console.error("Error restoring blog:", error);
      toast.error(error.response?.data?.message || "Failed to restore blog");
    }
  };

  // Handle profile update
  const handleProfileUpdate = async (e) => {
    e.preventDefault();
    if (editProfile.password !== editProfile.confirmPassword) {
      toast.error("Passwords do not match");
      return;
    }
    try {
      const { confirmPassword, ...updateData } = editProfile; // Exclude confirmPassword from API payload
      const res = await axios.put(`http://localhost:5000/api/update/${session.user.id}`, updateData);
      setAdminDetails(res.data.user);
      setEditProfile({
        username: res.data.user.username,
        email: res.data.user.email,
        phone: res.data.user.phone,
        password: "",
        confirmPassword: "",
      });
      setShowUpdateModal(false);
      toast.success(res.data.message);
    } catch (error) {
      console.error("Error updating profile:", error);
      toast.error(error.response?.data?.message || "Failed to update profile");
    }
  };

  // Sort trashed blogs
  const sortedTrashedBlogs = [...trashedBlogs].sort((a, b) => {
    const [sortBy, sortOrder] = sortOption.split("-");
    if (sortBy === "author") {
      const authorA = a.author?.username || "";
      const authorB = b.author?.username || "";
      return sortOrder === "asc" ? authorA.localeCompare(authorB) : authorB.localeCompare(authorA);
    } else {
      const dateA = new Date(a.deletedAt || a.createdAt);
      const dateB = new Date(b.deletedAt || b.createdAt);
      return sortOrder === "asc" ? dateA - dateB : dateB - dateA;
    }
  });

  // Show loading state while session is loading
  if (status === "loading") {
    return (
      <div className="flex min-h-screen items-center justify-center bg-[#fafafa]">
        <div className="h-10 w-10 animate-spin rounded-full border-4 border-t-indigo-600" />
      </div>
    );
  }

  return (
    <div className="bg-[#fafafa] min-h-screen">
      {/* Navbar */}
      <div className="w-full flex justify-between items-center px-6 md:px-12 py-4 shadow-md bg-white">
        <div className="text-4xl font-bold flex gap-3 items-center">
          <FaBlog />
          Admin Dashboard
        </div>
        <div className="flex items-center gap-4">
          <button
            onClick={() => setView("reported")}
            className={`px-6 py-2 font-bold text-sm transition ${
              view === "reported"
                ? "bg-black text-white shadow-[4px_4px_0_#000]"
                : "border border-black shadow-[4px_4px_0_#000] hover:shadow-[2px_2px_0_#000]"
            }`}
          >
            Reported Blogs
          </button>
          <button
            onClick={() => setView("all")}
            className={`px-6 py-2 font-bold text-sm transition ${
              view === "all"
                ? "bg-black text-white shadow-[4px_4px_0_#000]"
                : "border border-black shadow-[4px_4px_0_#000] hover:shadow-[2px_2px_0_#000]"
            }`}
          >
            Blog List
          </button>
          <button
            onClick={() => setShowProfileDropdown(!showProfileDropdown)}
            className="flex items-center gap-2"
          >
            <CgProfile className="text-4xl" />
          </button>
        </div>
      </div>

      {/* Profile Dropdown */}
      {showProfileDropdown && (
        <div className="absolute right-6 top-16 bg-white rounded-lg shadow-lg p-6 w-80 z-50">
          <h3 className="text-lg font-bold mb-4">Admin Profile</h3>
          <button
            onClick={() => setShowUpdateModal(true)}
            className="w-full flex items-center justify-center gap-2 bg-blue-600 text-white py-2 rounded hover:bg-blue-700 transition mb-4"
          >
            <FiEdit />
            Update Profile
          </button>
          <button
            onClick={() => {
              setView("trash");
              setShowProfileDropdown(false);
            }}
            className="w-full flex items-center justify-center gap-2 bg-yellow-600 text-white py-2 rounded hover:bg-yellow-700 transition mb-4"
          >
            <FaTrash />
            View Trash
          </button>
          <button
            onClick={() => signOut({ callbackUrl: "/homepage" })}
            className="w-full flex items-center justify-center gap-2 bg-red-600 text-white py-2 rounded hover:bg-red-700 transition"
          >
            <FiLogOut />
            Sign Out
          </button>
        </div>
      )}

      {/* Update Profile Modal */}
      {showUpdateModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-md">
            <h3 className="text-lg font-bold mb-4">Update Profile</h3>
            <form className="space-y-2" onSubmit={handleProfileUpdate}>
              <input
                type="text"
                placeholder="Username"
                value={editProfile.username}
                onChange={(e) => setEditProfile({ ...editProfile, username: e.target.value })}
                className="w-full border p-2 rounded text-sm"
              />
              <input
                type="email"
                placeholder="Email"
                value={editProfile.email}
                onChange={(e) => setEditProfile({ ...editProfile, email: e.target.value })}
                className="w-full border p-2 rounded text-sm"
              />
              <input
                type="tel"
                placeholder="Phone"
                value={editProfile.phone}
                onChange={(e) => setEditProfile({ ...editProfile, phone: e.target.value })}
                className="w-full border p-2 rounded text-sm"
              />
              <input
                type="password"
                placeholder="New Password (optional)"
                value={editProfile.password}
                onChange={(e) => setEditProfile({ ...editProfile, password: e.target.value })}
                className="w-full border p-2 rounded text-sm"
              />
              <input
                type="password"
                placeholder="Confirm New Password"
                value={editProfile.confirmPassword}
                onChange={(e) => setEditProfile({ ...editProfile, confirmPassword: e.target.value })}
                className="w-full border p-2 rounded text-sm"
              />
              <div className="flex gap-2">
                <button
                  type="submit"
                  className="w-full bg-blue-600 text-white py-2 rounded hover:bg-blue-700 transition"
                >
                  Save Changes
                </button>
                <button
                  type="button"
                  onClick={() => setShowUpdateModal(false)}
                  className="w-full bg-gray-600 text-white py-2 rounded hover:bg-gray-700 transition"
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Main Content */}
      <div className="max-w-5xl mx-auto px-4 py-8">
        {view === "reported" ? (
          <ReportedBlogs
            reportedBlogs={reportedBlogs}
            handleDenyReport={handleDenyReport}
            handleDeleteBlog={handleDeleteBlog}
          />
        ) : view === "all" ? (
          <BlogList
            allBlogs={allBlogs}
            sortBy={sortOption.split("-")[0]}
            sortOrder={sortOption.split("-")[1]}
            setSortBy={(by) => setSortOption(`${by}-${sortOption.split("-")[1]}`)}
            setSortOrder={(order) => setSortOption(`${sortOption.split("-")[0]}-${order}`)}
            handleDeleteBlog={handleDeleteBlog}
          />
        ) : (
          <>
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-3xl font-bold">Trashed Blogs</h2>
              <select
                value={sortOption}
                onChange={(e) => setSortOption(e.target.value)}
                className="border p-2 rounded text-sm"
              >
                <option value="createdAt-asc">Date (Ascending)</option>
                <option value="createdAt-desc">Date (Descending)</option>
                <option value="author-asc">Author (Ascending)</option>
                <option value="author-desc">Author (Descending)</option>
              </select>
            </div>
            {sortedTrashedBlogs.length > 0 ? (
              <div className="overflow-x-auto">
                <table className="w-full border-collapse bg-white shadow-md rounded-lg">
                  <thead>
                    <tr className="bg-gray-100">
                      <th className="p-3 text-left text-sm font-semibold text-gray-700">Thumbnail</th>
                      <th className="p-3 text-left text-sm font-semibold text-gray-700">Author</th>
                      <th className="p-3 text-left text-sm font-semibold text-gray-700">Title</th>
                      <th className="p-3 text-left text-sm font-semibold text-gray-700">Category</th>
                      <th className="p-3 text-left text-sm font-semibold text-gray-700">Deleted At</th>
                      <th className="p-3 text-left text-sm font-semibold text-gray-700">Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {sortedTrashedBlogs.map((blog) => (
                      <tr key={blog._id} className="border-b hover:bg-gray-50">
                        <td className="p-3">
                          {blog.thumbnail ? (
                            <img
                              src={blog.thumbnail}
                              alt={blog.title}
                              className="w-10 h-10 rounded-full object-cover"
                            />
                          ) : (
                            <div className="w-10 h-10 rounded-full bg-gray-200 flex items-center justify-center text-gray-500">
                              N/A
                            </div>
                          )}
                        </td>
                        <td className="p-3 text-sm text-gray-600">{blog.author?.username || "Unknown Author"}</td>
                        <td className="p-3 text-sm text-gray-600">{blog.title}</td>
                        <td className="p-3 text-sm text-gray-600">{blog.category || "Uncategorized"}</td>
                        <td className="p-3 text-sm text-gray-600">{new Date(blog.deletedAt).toLocaleDateString()}</td>
                        <td className="p-3">
                          <button
                            onClick={() => handleRestoreBlog(blog._id)}
                            className="bg-green-600 text-white px-3 py-1 rounded hover:bg-green-700 transition text-sm"
                          >
                            Restore
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            ) : (
              <p className="text-center text-gray-600">No trashed blogs found.</p>
            )}
          </>
        )}
      </div>
    </div>
  );
}




"use client";
import { useState, useEffect, useRef } from "react";
import { useRouter } from "next/navigation";
import { useSession, signOut } from "next-auth/react";
import axios from "axios";
import { toast } from "react-toastify";
import { FaBlog, FaTrash } from "react-icons/fa6";
import { CgProfile } from "react-icons/cg";
import { FiLogOut } from "react-icons/fi";
import BlogList from "./BlogList/page.js";
import ReportedBlogs from "./ReportedBlogs/page.js";

export default function AdminDashboard() {
  const router = useRouter();
  const { data: session, status } = useSession();
  const [reportedBlogs, setReportedBlogs] = useState([]);
  const [allBlogs, setAllBlogs] = useState([]);
  const [trashedBlogs, setTrashedBlogs] = useState([]);
  const [view, setView] = useState("reported"); // "reported", "all", or "trash"
  const [adminDetails, setAdminDetails] = useState(null);
  const [showProfileDropdown, setShowProfileDropdown] = useState(false);
  const [sortOption, setSortOption] = useState("createdAt-desc");
  const hasRedirected = useRef(false);
  const profileRef = useRef(null);

  // Click outside handler for profile dropdown
  useEffect(() => {
    function handleClickOutside(event) {
      if (profileRef.current && !profileRef.current.contains(event.target)) {
        setShowProfileDropdown(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, []);

  // Handle redirects in useEffect
  useEffect(() => {
    if (hasRedirected.current) return;

    if (status === "loading") return;

    if (status === "authenticated" && session?.user?.role !== "admin") {
      hasRedirected.current = true;
      router.push("/homepage");
    } else if (status === "unauthenticated") {
      hasRedirected.current = true;
      router.push("/homepage");
    }
  }, [status, session, router]);

  // Fetch admin details
  useEffect(() => {
    if (status === "authenticated" && session?.user?.id) {
      axios
        .get(`http://localhost:5000/api/user/${session.user.id}`)
        .then((response) => {
          setAdminDetails(response.data);
        })
        .catch((error) => {
          console.error("Error fetching admin details:", error);
          toast.error("Failed to fetch admin details");
        });
    }
  }, [status, session]);

  // Fetch reported blogs
  useEffect(() => {
    if (view === "reported") {
      axios
        .get("http://localhost:5000/api/reportblogs")
        .then((response) => {
          console.log("Reported blogs response:", response.data); // Debug log
          const blogs = Array.isArray(response.data) ? response.data : response.data.blogs || [];
          setReportedBlogs(blogs);
        })
        .catch((error) => {
          console.error("Error fetching reported blogs:", error);
          toast.error("Failed to fetch reported blogs");
        });
    }
  }, [view]);

  // Fetch all blogs
  useEffect(() => {
    if (view === "all") {
      axios
        .get("http://localhost:5000/api/bloglist")
        .then((response) => {
          console.log("All blogs response:", response.data); // Debug log
          const blogs = response.data.blogs || [];
          setAllBlogs(blogs);
        })
        .catch((error) => {
          console.error("Error fetching all blogs:", error);
          toast.error("Failed to fetch blogs");
        });
    }
  }, [view]);

  // Fetch trashed blogs
  useEffect(() => {
    if (view === "trash") {
      axios
        .get("http://localhost:5000/api/admintrash")
        .then((response) => {
          console.log("Trashed blogs response:", response.data); // Debug log
          const blogs = response.data.blogs || [];
          setTrashedBlogs(blogs);
        })
        .catch((error) => {
          console.error("Error fetching trashed blogs:", error);
          toast.error("Failed to fetch trashed blogs");
        });
    }
  }, [view]);

  // Handle deny report
  const handleDenyReport = async (blogId) => {
    try {
      const res = await axios.patch(`http://localhost:5000/api/denyreport/${blogId}`);
      setReportedBlogs(reportedBlogs.filter((blog) => blog._id !== blogId));
      toast.success(res.data.message);
    } catch (error) {
      console.error("Error denying report:", error);
      toast.error(error.response?.data?.message || "Failed to deny report");
    }
  };

  // Handle delete blog
  const handleDeleteBlog = async (blogId) => {
    try {
      const res = await axios.delete(`http://localhost:5000/api/admindelblog/${blogId}`);
      if (view === "reported") {
        setReportedBlogs(reportedBlogs.filter((blog) => blog._id !== blogId));
      } else if (view === "all") {
        setAllBlogs(allBlogs.filter((blog) => blog._id !== blogId));
      }
      toast.success(res.data.message);
    } catch (error) {
      console.error("Error deleting blog:", error);
      toast.error(error.response?.data?.message || "Failed to delete blog");
    }
  };

  // Handle restore blog
  const handleRestoreBlog = async (blogId) => {
    try {
      const res = await axios.put(`http://localhost:5000/api/adminrestore/${blogId}`);
      setTrashedBlogs(trashedBlogs.filter((blog) => blog._id !== blogId));
      toast.success(res.data.message);
    } catch (error) {
      console.error("Error restoring blog:", error);
      toast.error(error.response?.data?.message || "Failed to restore blog");
    }
  };

  // Sort trashed blogs
  const sortedTrashedBlogs = [...trashedBlogs].sort((a, b) => {
    const [sortBy, sortOrder] = sortOption.split("-");
    if (sortBy === "author") {
      const authorA = a.author?.username || "";
      const authorB = b.author?.username || "";
      return sortOrder === "asc" ? authorA.localeCompare(authorB) : authorB.localeCompare(authorA);
    } else {
      const dateA = new Date(a.deletedAt || a.createdAt);
      const dateB = new Date(b.deletedAt || b.createdAt);
      return sortOrder === "asc" ? dateA - dateB : dateB - dateA;
    }
  });

  // Show loading state while session is loading
  if (status === "loading") {
    return (
      <div className="flex min-h-screen items-center justify-center bg-gradient-to-r from-gray-50 to-gray-100">
        <div className="h-12 w-12 animate-spin rounded-full border-4 border-t-indigo-600 border-indigo-200"></div>
      </div>
    );
  }

  return (
    <div className="bg-gradient-to-r from-gray-50 to-gray-100 min-h-screen">
      {/* Navbar */}
      <div className="w-full flex justify-between items-center px-6 md:px-12 py-4 bg-white shadow-lg">
        <div className="text-4xl font-bold flex gap-3 items-center bg-gradient-to-r from-indigo-600 to-blue-500 bg-clip-text text-transparent">
          <FaBlog className="text-indigo-600" />
          Admin Dashboard
        </div>
        <div className="flex items-center gap-4">
          <button
            onClick={() => setView("reported")}
            className={`px-6 py-2 rounded-lg font-semibold text-sm transition-all duration-300 transform hover:scale-105 ${
              view === "reported"
                ? "bg-gradient-to-r from-indigo-600 to-blue-500 text-white"
                : "bg-white text-gray-700 hover:bg-gray-100"
            } shadow-md`}
          >
            Reported Blogs
          </button>
          <button
            onClick={() => setView("all")}
            className={`px-6 py-2 rounded-lg font-semibold text-sm transition-all duration-300 transform hover:scale-105 ${
              view === "all"
                ? "bg-gradient-to-r from-indigo-600 to-blue-500 text-white"
                : "bg-white text-gray-700 hover:bg-gray-100"
            } shadow-md`}
          >
            Blog List
          </button>
          <div ref={profileRef} className="relative">
            <button
              onClick={() => setShowProfileDropdown(!showProfileDropdown)}
              className="flex items-center gap-2 p-2 rounded-full bg-gray-100 hover:bg-gray-200 transition-all duration-300"
            >
              <CgProfile className="text-2xl text-indigo-600" />
            </button>
          </div>
        </div>
      </div>

      {/* Profile Dropdown */}
      {showProfileDropdown && (
        <div className="absolute right-6 top-16 bg-white rounded-lg shadow-xl p-6 w-80 z-50 transform transition-all duration-300 scale-100 opacity-100">
          <h3 className="text-lg font-bold mb-4 text-gray-800">
            {adminDetails?.username || "Admin"} Profile
          </h3>
          <div className="space-y-2 mb-4">
            <p className="text-sm text-gray-600">
              <span className="font-semibold">Email:</span> {adminDetails?.email}
            </p>
            {adminDetails?.phone && (
              <p className="text-sm text-gray-600">
                <span className="font-semibold">Phone:</span> {adminDetails.phone}
              </p>
            )}
          </div>
          <button
            onClick={() => {
              setView("trash");
              setShowProfileDropdown(false);
            }}
            className="w-full flex items-center justify-center gap-2 bg-gradient-to-r from-amber-500 to-orange-500 text-white py-2 rounded-lg hover:from-amber-600 hover:to-orange-600 transition-all duration-300 mb-3 transform hover:scale-105"
          >
            <FaTrash />
            View Trash
          </button>
          <button
            onClick={() => signOut({ callbackUrl: "/homepage" })}
            className="w-full flex items-center justify-center gap-2 bg-gradient-to-r from-red-500 to-pink-500 text-white py-2 rounded-lg hover:from-red-600 hover:to-pink-600 transition-all duration-300 transform hover:scale-105"
          >
            <FiLogOut />
            Sign Out
          </button>
        </div>
      )}

      {/* Main Content */}
      <div className="max-w-6xl mx-auto px-4 py-8">
        {view === "reported" ? (
          <ReportedBlogs
            reportedBlogs={reportedBlogs}
            handleDenyReport={handleDenyReport}
            handleDeleteBlog={handleDeleteBlog}
          />
        ) : view === "all" ? (
          <BlogList
            allBlogs={allBlogs}
            sortBy={sortOption.split("-")[0]}
            sortOrder={sortOption.split("-")[1]}
            setSortBy={(by) => setSortOption(`${by}-${sortOption.split("-")[1]}`)}
            setSortOrder={(order) => setSortOption(`${sortOption.split("-")[0]}-${order}`)}
            handleDeleteBlog={handleDeleteBlog}
          />
        ) : (
          <>
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-3xl font-bold bg-gradient-to-r from-indigo-600 to-blue-500 bg-clip-text text-transparent">
                Trashed Blogs
              </h2>
              <div className="flex items-center">
                <select
                  value={sortOption}
                  onChange={(e) => setSortOption(e.target.value)}
                  className="border border-gray-200 p-2 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-white shadow-sm"
                >
                  <option value="createdAt-asc">Date (Ascending)</option>
                  <option value="createdAt-desc">Date (Descending)</option>
                  <option value="author-asc">Author (Ascending)</option>
                  <option value="author-desc">Author (Descending)</option>
                </select>
              </div>
            </div>
            {sortedTrashedBlogs.length > 0 ? (
              <div className="overflow-x-auto rounded-xl shadow-xl">
                <table className="w-full bg-white rounded-xl overflow-hidden">
                  <thead>
                    <tr className="bg-gradient-to-r from-gray-100 to-gray-200">
                      <th className="p-4 text-left text-sm font-semibold text-gray-700">Thumbnail</th>
                      <th className="p-4 text-left text-sm font-semibold text-gray-700">Author</th>
                      <th className="p-4 text-left text-sm font-semibold text-gray-700">Title</th>
                      <th className="p-4 text-left text-sm font-semibold text-gray-700">Category</th>
                      <th className="p-4 text-left text-sm font-semibold text-gray-700">Deleted At</th>
                      <th className="p-4 text-left text-sm font-semibold text-gray-700">Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {sortedTrashedBlogs.map((blog) => (
                      <tr key={blog._id} className="border-b hover:bg-gray-50 transition-colors duration-200">
                        <td className="p-4">
                          {blog.thumbnail ? (
                            <img
                              src={blog.thumbnail}
                              alt={blog.title}
                              className="w-12 h-12 rounded-full object-cover shadow-sm border-2 border-gray-100"
                            />
                          ) : (
                            <div className="w-12 h-12 rounded-full bg-gradient-to-r from-gray-200 to-gray-300 flex items-center justify-center text-gray-500">
                              N/A
                            </div>
                          )}
                        </td>
                        <td className="p-4 text-sm text-gray-700">{blog.author?.username || "Unknown Author"}</td>
                        <td className="p-4 text-sm text-gray-700">{blog.title}</td>
                        <td className="p-4 text-sm text-gray-700">
                          <span className="px-2 py-1 bg-gray-100 rounded-full text-xs">
                            {blog.category || "Uncategorized"}
                          </span>
                        </td>
                        <td className="p-4 text-sm text-gray-700">{new Date(blog.deletedAt).toLocaleDateString()}</td>
                        <td className="p-4">
                          <button
                            onClick={() => handleRestoreBlog(blog._id)}
                            className="bg-gradient-to-r from-emerald-500 to-green-500 text-white px-4 py-2 rounded-lg hover:from-emerald-600 hover:to-green-600 transition-all duration-300 text-sm transform hover:scale-105 shadow-md"
                          >
                            Restore
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            ) : (
              <div className="text-center p-12 bg-white rounded-xl shadow-lg">
                <div className="text-6xl text-gray-300 mb-4">
                  <FaTrash className="mx-auto" />
                </div>
                <p className="text-gray-600 text-lg">No trashed blogs found.</p>
                <p className="text-gray-500 text-sm mt-2">When blogs are deleted, they will appear here.</p>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}