"use client";
import { useState } from "react";
import { BiShieldX, BiTrash, BiCheckShield } from "react-icons/bi";

function ReportedBlogs({ reportedBlogs, handleDenyReport, handleDeleteBlog }) {
  const [sortOption, setSortOption] = useState("reports-desc");
  const [expandedBlog, setExpandedBlog] = useState(null);

  // Sorting function
  const sortedBlogs = [...reportedBlogs].sort((a, b) => {
    switch (sortOption) {
      case "title-asc":
        return a.title.localeCompare(b.title);
      case "title-desc":
        return b.title.localeCompare(a.title);
      case "reports-asc":
        return a.reports.length - b.reports.length;
      case "reports-desc":
        return b.reports.length - a.reports.length;
      case "date-asc":
        return new Date(a.createdAt) - new Date(b.createdAt);
      case "date-desc":
        return new Date(b.createdAt) - new Date(a.createdAt);
      default:
        return 0;
    }
  });

  // Toggle expanded description
  const toggleExpand = (blogId) => {
    if (expandedBlog === blogId) {
      setExpandedBlog(null);
    } else {
      setExpandedBlog(blogId);
    }
  };

  return (
    <>
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-8 gap-4">
        <h2 className="text-2xl sm:text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-rose-600 to-purple-600">
          Flagged Content Review
        </h2>
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <label htmlFor="sort" className="text-sm font-medium text-gray-600">
            Sort by:
          </label>
          <div className="relative w-full sm:w-auto">
            <select
              id="sort"
              value={sortOption}
              onChange={(e) => setSortOption(e.target.value)}
              className="appearance-none w-full bg-gradient-to-r from-gray-50 to-gray-100 border-0 rounded-xl py-2.5 px-4 pr-10 text-sm shadow-md hover:shadow-lg transition-all duration-300 focus:outline-none focus:ring-2 focus:ring-purple-400"
            >
              <option value="reports-desc">Most Reports</option>
              <option value="reports-asc">Fewest Reports</option>
              <option value="title-asc">Title (A-Z)</option>
              <option value="title-desc">Title (Z-A)</option>
              <option value="date-desc">Newest</option>
              <option value="date-asc">Oldest</option>
            </select>
            <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-3 text-gray-500">
              <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20">
                <path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z" />
              </svg>
            </div>
          </div>
        </div>
      </div>
      
      {sortedBlogs.length > 0 ? (
        <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
          {sortedBlogs.map((blog) => (
            <div
              key={blog._id}
              className="relative rounded-xl overflow-hidden shadow-lg hover:shadow-xl transition-all duration-300 bg-white group"
            >
              {/* Report count badge */}
              <div className="absolute top-3 right-3 bg-gradient-to-r from-red-500 to-pink-500 text-white text-xs font-bold rounded-full px-3 py-1 z-10 shadow-md">
                {blog.reports.length} {blog.reports.length === 1 ? "report" : "reports"}
              </div>
              
              {/* Blog thumbnail */}
              <div className="relative w-full h-48 overflow-hidden">
                {blog.thumbnail ? (
                  <img
                    src={blog.thumbnail}
                    alt={blog.title}
                    className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                  />
                ) : (
                  <div className="w-full h-full bg-gradient-to-br from-gray-200 to-gray-300 flex items-center justify-center">
                    <span className="text-gray-500 font-medium">No Image</span>
                  </div>
                )}
                
                {/* Gradient overlay */}
                <div className="absolute inset-x-0 bottom-0 h-16 bg-gradient-to-t from-black/70 to-transparent"></div>
                
                {/* Author info */}
                <div className="absolute bottom-3 left-3 flex items-center">
                  <div className="w-7 h-7 rounded-full bg-gradient-to-br from-purple-500 to-pink-500 flex items-center justify-center text-white font-medium text-xs shadow-md">
                    {blog.author?.username?.[0]?.toUpperCase() || "?"}
                  </div>
                  <span className="ml-2 text-xs text-white font-medium drop-shadow-md">
                    {blog.author?.username || "Unknown Author"}
                  </span>
                </div>
              </div>
              
              {/* Blog content */}
              <div className="p-5">
                <h3 className="text-lg font-bold mb-3 text-gray-800 line-clamp-1">{blog.title}</h3>
                
                <div className="mb-4">
                  <p className={`text-sm text-gray-600 ${expandedBlog === blog._id ? "" : "line-clamp-3"}`}>
                    {blog.description}
                  </p>
                  {blog.description && blog.description.split(" ").length > 20 && (
                    <button
                      onClick={() => toggleExpand(blog._id)}
                      className="text-xs font-medium text-purple-600 hover:text-purple-800 transition-colors mt-1 focus:outline-none"
                    >
                      {expandedBlog === blog._id ? "Show less" : "Read more"}
                    </button>
                  )}
                </div>
                
                <div className="flex items-center justify-between text-xs text-gray-500 mb-4">
                  <div className="flex items-center">
                    <BiShieldX className="text-red-500 mr-1" />
                    <span>Flagged content</span>
                  </div>
                  <span>
                    {new Date(blog.createdAt).toLocaleDateString("en-US", {
                      month: "short",
                      day: "numeric",
                      year: "numeric"
                    })}
                  </span>
                </div>
                
                {/* Action buttons */}
                <div className="flex gap-3">
                  <button
                    onClick={() => handleDenyReport(blog._id)}
                    className="flex-1 bg-gradient-to-r from-emerald-500 to-teal-500 text-white py-2.5 rounded-lg hover:from-emerald-600 hover:to-teal-600 transition-all duration-300 flex items-center justify-center gap-1 shadow-md hover:shadow-lg transform hover:translate-y-px active:translate-y-0"
                  >
                    <BiCheckShield className="text-lg" />
                    <span className="font-medium">Deny</span>
                  </button>
                  <button
                    onClick={() => handleDeleteBlog(blog._id)}
                    className="flex-1 bg-gradient-to-r from-red-500 to-rose-500 text-white py-2.5 rounded-lg hover:from-red-600 hover:to-rose-600 transition-all duration-300 flex items-center justify-center gap-1 shadow-md hover:shadow-lg transform hover:translate-y-px active:translate-y-0"
                  >
                    <BiTrash className="text-lg" />
                    <span className="font-medium">Remove</span>
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="rounded-xl bg-gradient-to-r from-gray-50 to-gray-100 p-12 text-center shadow-md">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-gradient-to-r from-purple-100 to-indigo-100 mb-4">
            <BiCheckShield className="text-3xl text-purple-500" />
          </div>
          <p className="text-lg text-gray-600 font-medium">No reported content to review</p>
          <p className="text-sm text-gray-500 mt-2">All flagged blogs have been processed</p>
        </div>
      )}

      <style jsx global>{`
        @keyframes pulse {
          0%, 100% {
            opacity: 1;
          }
          50% {
            opacity: 0.7;
          }
        }
        
        .line-clamp-1 {
          display: -webkit-box;
          -webkit-line-clamp: 1;
          -webkit-box-orient: vertical;
          overflow: hidden;
        }
        
        .line-clamp-3 {
          display: -webkit-box;
          -webkit-line-clamp: 3;
          -webkit-box-orient: vertical;
          overflow: hidden;
        }
      `}</style>
    </>
  );
}

export default ReportedBlogs;