"use client";
import { useMemo, useState, useRef, useEffect } from "react";
import { BiSolidLike, BiSolidDislike, BiSolidFlag } from "react-icons/bi";

function BlogList({ allBlogs, sortBy, sortOrder, setSortBy, setSortOrder, handleDeleteBlog }) {
  // State for modal visibility and selected blog
  const [showModal, setShowModal] = useState(false);
  const [selectedBlog, setSelectedBlog] = useState(null);
  const modalRef = useRef(null);

  // Sort blogs based on sortBy and sortOrder
  const sortedBlogs = useMemo(() => {
    return [...allBlogs].sort((a, b) => {
      if (sortBy === "author") {
        const authorA = a.author?.username?.toLowerCase() || "";
        const authorB = b.author?.username?.toLowerCase() || "";
        return sortOrder === "asc"
          ? authorA.localeCompare(authorB)
          : authorB.localeCompare(authorA);
      } else {
        // sortBy === "createdAt"
        const dateA = new Date(a.createdAt).getTime();
        const dateB = new Date(b.createdAt).getTime();
        return sortOrder === "asc" ? dateA - dateB : dateB - dateA;
      }
    });
  }, [allBlogs, sortBy, sortOrder]);

  // Function to open modal with the selected blog
  const openModal = (blog) => {
    setSelectedBlog(blog);
    setShowModal(true);
  };

  // Function to close modal
  const closeModal = () => {
    setShowModal(false);
    setSelectedBlog(null);
  };

  // Handle outside click to close modal
  useEffect(() => {
    const handleOutsideClick = (event) => {
      if (showModal && modalRef.current && !modalRef.current.contains(event.target)) {
        closeModal();
      }
    };
    document.addEventListener("mousedown", handleOutsideClick);
    return () => document.removeEventListener("mousedown", handleOutsideClick);
  }, [showModal]);

  // Function to get first three words of description
  const getTruncatedDescription = (description) => {
    if (!description) return "No description...";
    const words = description.trim().split(/\s+/);
    return words.length > 3 ? words.slice(0, 3).join(" ") + "..." : description + "...";
  };

  // Handle row click, excluding the delete button
  const handleRowClick = (e, blog) => {
    // Prevent modal from opening if the delete button or its children are clicked
    if (e.target.closest("button")) {
      return;
    }
    openModal(blog);
  };

  return (
    <>
      <h2 className="text-2xl sm:text-3xl font-bold mb-8 text-transparent bg-clip-text bg-gradient-to-r from-indigo-600 to-purple-600">Blog Collection</h2>
      {allBlogs.length > 0 ? (
        <div className="space-y-6">
          <div className="flex items-center gap-4">
            <label className="text-sm font-semibold text-gray-700">Sort by:</label>
            <div className="relative">
              <select
                value={`${sortBy}-${sortOrder}`}
                onChange={(e) => {
                  const [newSortBy, newSortOrder] = e.target.value.split("-");
                  setSortBy(newSortBy);
                  setSortOrder(newSortOrder);
                }}
                className="appearance-none bg-white border-0 px-4 py-2 rounded-xl text-sm w-full sm:w-auto pr-10 focus:outline-none shadow-md hover:shadow-lg transition-shadow duration-300 bg-gradient-to-r from-gray-50 to-gray-100"
              >
                <option value="createdAt-desc">Date (Newest First)</option>
                <option value="createdAt-asc">Date (Oldest First)</option>
                <option value="author-asc">Author (A-Z)</option>
                <option value="author-desc">Author (Z-A)</option>
              </select>
              <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-gray-700">
                <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20">
                  <path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z" />
                </svg>
              </div>
            </div>
          </div>
          
          <div className="overflow-x-auto rounded-xl">
            <table className="w-full bg-white shadow-xl rounded-xl overflow-hidden">
              <thead>
                <tr className="bg-gradient-to-r from-indigo-500 to-purple-600 text-white">
                  <th className="p-3 sm:p-4 text-left text-xs sm:text-sm font-medium tracking-wider">Thumbnail</th>
                  <th className="p-3 sm:p-4 text-left text-xs sm:text-sm font-medium tracking-wider">Author</th>
                  <th className="p-3 sm:p-4 text-left text-xs sm:text-sm font-medium tracking-wider">Title</th>
                  <th className="p-3 sm:p-4 text-left text-xs sm:text-sm font-medium tracking-wider">Category</th>
                  <th className="p-3 sm:p-4 text-left text-xs sm:text-sm font-medium tracking-wider">Description</th>
                  <th className="p-3 sm:p-4 text-left text-xs sm:text-sm font-medium tracking-wider">Action</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {sortedBlogs.map((blog) => (
                  <tr
                    key={blog._id}
                    className="hover:bg-gray-50 cursor-pointer transition-all duration-300 ease-in-out"
                    onClick={(e) => handleRowClick(e, blog)}
                  >
                    <td className="p-3 sm:p-4">
                      {blog.thumbnail ? (
                        <img
                          src={blog.thumbnail}
                          alt={blog.title}
                          className="w-10 h-10 sm:w-12 sm:h-12 rounded-lg object-cover shadow-md hover:shadow-lg transition-all duration-300 ease-in-out transform hover:scale-105"
                        />
                      ) : (
                        <div className="w-10 h-10 sm:w-12 sm:h-12 rounded-lg bg-gradient-to-br from-gray-200 to-gray-300 flex items-center justify-center text-gray-500 text-xs shadow-sm">
                          No Image
                        </div>
                      )}
                    </td>
                    <td className="p-3 sm:p-4 text-xs sm:text-sm text-gray-600 font-medium">{blog.author?.username || "Unknown Author"}</td>
                    <td className="p-3 sm:p-4 text-xs sm:text-sm text-gray-800 font-semibold">{blog.title}</td>
                    <td className="p-3 sm:p-4">
                      <span className="px-2.5 py-1 rounded-full text-xs font-medium bg-gradient-to-r from-indigo-100 to-purple-100 text-indigo-800">
                        {blog.category || "Uncategorized"}
                      </span>
                    </td>
                    <td className="p-3 sm:p-4 text-xs sm:text-sm text-gray-600">{getTruncatedDescription(blog.description)}</td>
                    <td className="p-3 sm:p-4">
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleDeleteBlog(blog._id);
                        }}
                        className="bg-gradient-to-r from-red-500 to-pink-500 text-white px-3 py-1 sm:px-4 sm:py-1.5 rounded-lg hover:from-red-600 hover:to-pink-600 transition-all duration-300 text-xs sm:text-sm font-medium shadow-md hover:shadow-lg transform hover:scale-105 active:scale-95"
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      ) : (
        <div className="bg-gradient-to-r from-gray-50 to-gray-100 p-10 rounded-xl shadow-md text-center">
          <p className="text-center text-gray-600 text-base sm:text-lg">No blogs found.</p>
        </div>
      )}

      {/* Post-Style Modal */}
      {showModal && selectedBlog && (
        <div className="fixed inset-0 bg-black bg-opacity-70 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-fade-in">
          <div
            ref={modalRef}
            className="relative bg-white rounded-2xl shadow-2xl w-full max-w-[90vw] sm:max-w-md md:max-w-lg max-h-[90vh] overflow-y-auto no-scrollbar transform transition-all duration-500 scale-100 hover:scale-[1.01] animate-slide-up"
            style={{
              animation: "slideUp 0.4s ease-out forwards",
              boxShadow: "0 10px 40px rgba(0, 0, 0, 0.2)"
            }}
          >
            {/* Close Button */}
            <button
              onClick={closeModal}
              className="absolute top-4 right-4 text-gray-400 hover:text-gray-800 text-xl sm:text-2xl z-10 transition-colors duration-300 bg-white bg-opacity-70 backdrop-blur-sm rounded-full w-8 h-8 flex items-center justify-center"
            >
              ×
            </button>

            {/* Post Header */}
            <div className="flex items-center p-4 sm:p-5 border-b border-gray-100">
              <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-white font-bold text-base sm:text-lg shadow-md">
                {selectedBlog.author?.username?.[0]?.toUpperCase() || "U"}
              </div>
              <div className="ml-3 sm:ml-4">
                <p className="text-xs sm:text-sm font-semibold text-gray-800">{selectedBlog.author?.username || "Unknown Author"}</p>
                <div className="flex items-center mt-1">
                  <span className="inline-block w-2 h-2 rounded-full bg-gradient-to-r from-green-400 to-green-500 mr-1.5"></span>
                  <p className="text-xs text-gray-500">{selectedBlog.category || "Uncategorized"}</p>
                </div>
              </div>
            </div>

            {/* Post Image */}
            {selectedBlog.thumbnail && (
              <div className="w-full h-48 sm:h-64 md:h-72 overflow-hidden">
                <img
                  src={selectedBlog.thumbnail}
                  alt={selectedBlog.title}
                  className="w-full h-full object-cover transition-transform duration-700 hover:scale-105"
                />
              </div>
            )}

            {/* Post Content */}
            <div className="p-5 sm:p-6">
              {/* Title */}
              <h2 className="text-lg sm:text-xl md:text-2xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-indigo-600 to-purple-600 mb-3">{selectedBlog.title}</h2>

              {/* Description */}
              <p className="text-gray-700 text-xs sm:text-sm md:text-base mb-6 whitespace-pre-wrap leading-relaxed">
                {selectedBlog.description}
              </p>

              {/* Engagement Metrics */}
              <div className="flex items-center gap-4 sm:gap-6 text-xs sm:text-sm text-gray-600 pt-4 border-t border-gray-100">
                <div className="flex items-center gap-1 bg-blue-50 px-3 py-1.5 rounded-full transition-all duration-300 hover:bg-blue-100">
                  <BiSolidLike className="text-blue-500" />
                  <span className="font-medium">{selectedBlog.likes?.length || 0}</span>
                </div>
                <div className="flex items-center gap-1 bg-red-50 px-3 py-1.5 rounded-full transition-all duration-300 hover:bg-red-100">
                  <BiSolidDislike className="text-red-500" />
                  <span className="font-medium">{selectedBlog.dislikes?.length || 0}</span>
                </div>
                <div className="flex items-center gap-1 bg-orange-50 px-3 py-1.5 rounded-full transition-all duration-300 hover:bg-orange-100">
                  <BiSolidFlag className="text-orange-500" />
                  <span className="font-medium">{selectedBlog.reports?.length || 0}</span>
                </div>
              </div>

              {/* Post Date */}
              <p className="text-xs text-gray-400 mt-5">
                Posted on {new Date(selectedBlog.createdAt).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}
              </p>
            </div>

            {/* Close Button (Bottom) */}
            <div className="p-5 sm:p-6">
              <button
                onClick={closeModal}
                className="w-full bg-gradient-to-r from-indigo-500 to-purple-600 text-white px-4 py-3 rounded-xl hover:from-indigo-600 hover:to-purple-700 transition-all duration-300 font-medium text-sm sm:text-base shadow-md hover:shadow-lg transform hover:translate-y-px active:translate-y-0"
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}

      <style jsx global>{`
        @keyframes slideUp {
          from {
            opacity: 0;
            transform: translateY(20px) scale(0.98);
          }
          to {
            opacity: 1;
            transform: translateY(0) scale(1);
          }
        }
        
        @keyframes fade-in {
          from {
            opacity: 0;
          }
          to {
            opacity: 1;
          }
        }
        
        .no-scrollbar::-webkit-scrollbar {
          display: none;
        }
        
        .no-scrollbar {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
      `}</style>
    </>
  );
}

export default BlogList;